string toHex(long long num) {
    if (num == 0) return "0";
    string hex;
    while (num > 0) {
        int rem = num % 16;
        if (rem < 10) {
            hex += '0' + rem;
        } else {
            hex += 'A' + (rem - 10);
        }
        num /= 16;
    }
    reverse(hex.begin(), hex.end());
    return hex;
}

