using namespace std;

string toHex(long long num) {
    if (num == 0) return "0";
    string hex;
    while (num > 0) {
        int rem = num % 16;
        char c;
        if (rem < 10) {
            c = '0' + rem;
        } else {
            c = 'A' + (rem - 10);
        }
        hex.push_back(c);
        num /= 16;
    }
    reverse(hex.begin(), hex.end());
    return hex;
}

string toBase36(long long num) {
    if (num == 0) return "0";
    string base36;
    while (num > 0) {
        int rem = num % 36;
        char c;
        if (rem < 10) {
            c = '0' + rem;
        } else {
            c = 'A' + (rem - 10);
        }
        base36.push_back(c);
        num /= 36;
    }
    reverse(base36.begin(), base36.end());
    return base36;
}

string solve(long long n) {
    long long n2 = n * n;
